import { useEffect } from 'react';
import { useStatsStore } from './statsStore';
import { useStreakStore } from '../daily/streakStore';
import './stats.css';

interface Props {
  onClose: () => void;
}

function formatTime(ms: number | null): string {
  if (ms == null) return '—';
  const totalSec = Math.floor(ms / 1000);
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return `${m}:${String(s).padStart(2, '0')}`;
}

function winRate(w: number, l: number): string {
  const total = w + l;
  if (total === 0) return '—';
  return `${Math.round((w / total) * 100)}%`;
}

const DIFFS = [
  { key: 'lite', label: 'Lite' },
  { key: 'beginner', label: 'Beginner' },
  { key: 'intermediate', label: 'Intermediate' },
  { key: 'expert', label: 'Expert' },
] as const;

export default function StatsSheet({ onClose }: Props) {
  const {
    totalWins,
    totalLosses,
    noGuessStreak,
    longestCascade,
    byDifficulty,
  } = useStatsStore();
  const dailyStreak = useStreakStore((s) => s.current);
  const dailyLongest = useStreakStore((s) => s.longest);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [onClose]);

  return (
    <div
      className="ms-sheet-backdrop"
      onClick={onClose}
      role="presentation"
    >
      <div
        className="ms-sheet ms-stats-sheet"
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-label="Personal stats"
        data-testid="ms-stats-sheet"
      >
        <p className="ms-settings-title">Your stats</p>

        <div className="ms-stats-overview">
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{totalWins}</span>
            <span className="ms-stats-label">Wins</span>
          </div>
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{totalLosses}</span>
            <span className="ms-stats-label">Losses</span>
          </div>
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{winRate(totalWins, totalLosses)}</span>
            <span className="ms-stats-label">Win rate</span>
          </div>
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{noGuessStreak}</span>
            <span className="ms-stats-label">No-guess streak</span>
          </div>
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{dailyStreak}</span>
            <span className="ms-stats-label">Daily streak</span>
          </div>
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{dailyLongest}</span>
            <span className="ms-stats-label">Longest daily</span>
          </div>
          <div className="ms-stats-tile">
            <span className="ms-stats-value">{longestCascade}</span>
            <span className="ms-stats-label">Longest cascade</span>
          </div>
        </div>

        <div className="ms-stats-table" aria-label="Per-difficulty stats">
          <div className="ms-stats-row ms-stats-row-head">
            <span>Difficulty</span>
            <span>Best</span>
            <span>Wins</span>
            <span>Losses</span>
          </div>
          {DIFFS.map(({ key, label }) => {
            const d = byDifficulty[key];
            return (
              <div className="ms-stats-row" key={key} data-difficulty={key}>
                <span>{label}</span>
                <span className="ms-stats-best">{formatTime(d.bestTimeMs)}</span>
                <span>{d.wins}</span>
                <span>{d.losses}</span>
              </div>
            );
          })}
        </div>

        <button className="ms-settings-close" onClick={onClose} type="button">
          Done
        </button>
      </div>
    </div>
  );
}
